/**
 * Template for generating repository files
 */

import { toPascalCase, toTableName } from '../generators/utils.js';

export function generateRepositoryTemplate(entityName: string): string {
  const pascalName = toPascalCase(entityName);
  const tableName = toTableName(entityName);

  return `/**
 * @generated by @flusk/cli from ${entityName}.entity.ts
 * DO NOT EDIT - regenerate using: flusk g ${entityName}.entity.ts
 */

import { Pool } from 'pg';
import { ${pascalName}Entity } from '@flusk/entities';

/**
 * PostgreSQL connection pool singleton
 */
let pool: Pool | null = null;

/**
 * Get or create PostgreSQL connection pool
 */
function getPool(): Pool {
  if (!pool) {
    const connectionString = process.env.DATABASE_URL;
    if (!connectionString) {
      throw new Error('DATABASE_URL environment variable is required');
    }

    pool = new Pool({
      connectionString,
      max: 20,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000
    });

    pool.on('error', (err) => {
      console.error('Unexpected database error:', err);
    });
  }

  return pool;
}

/**
 * Convert database row to ${pascalName}Entity
 */
function rowToEntity(row: any): ${pascalName}Entity {
  return {
    id: row.id,
    createdAt: row.created_at.toISOString(),
    updatedAt: row.updated_at.toISOString(),
    // TODO: Add field mappings from schema
  } as ${pascalName}Entity;
}

/**
 * Create a new ${entityName} record
 */
export async function create(
  data: Omit<${pascalName}Entity, 'id' | 'createdAt' | 'updatedAt'>
): Promise<${pascalName}Entity> {
  const db = getPool();

  // TODO: Add actual fields from schema
  const query = \`
    INSERT INTO ${tableName} (
      -- Add columns here
    ) VALUES (
      -- Add values here
    )
    RETURNING *
  \`;

  const result = await db.query(query);
  return rowToEntity(result.rows[0]);
}

/**
 * Find ${entityName} by UUID
 */
export async function findById(id: string): Promise<${pascalName}Entity | null> {
  const db = getPool();

  const query = 'SELECT * FROM ${tableName} WHERE id = $1';
  const result = await db.query(query, [id]);

  if (result.rows.length === 0) {
    return null;
  }

  return rowToEntity(result.rows[0]);
}

/**
 * Update ${entityName} record
 */
export async function update(
  id: string,
  data: Partial<Omit<${pascalName}Entity, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<${pascalName}Entity | null> {
  const db = getPool();

  // TODO: Implement dynamic update logic
  const query = \`
    UPDATE ${tableName}
    SET updated_at = NOW()
    WHERE id = $1
    RETURNING *
  \`;

  const result = await db.query(query, [id]);

  if (result.rows.length === 0) {
    return null;
  }

  return rowToEntity(result.rows[0]);
}

/**
 * Close database connection pool
 */
export async function closePool(): Promise<void> {
  if (pool) {
    await pool.end();
    pool = null;
  }
}
`;
}
